def close(self) -> None:
    """Invoke all close callbacks registered with
    :meth:`call_on_close`, and exit all context managers entered
    with :meth:`with_resource`.
    """
    self._exit_stack.close()
    # In case the context is reused, create a new exit stack.
    self._exit_stack = ExitStack()

@property
def command_path(self) -> str:
    """The computed command path.  This is used for the ``usage``
    information on the help page.  It's automatically created by
    combining the info names of the chain of contexts to the root.
    """
    rv = ""
    if self.info_name is not None:
        rv = self.info_name
    if self.parent is not None:
        parent_command_path = [self.parent.command_path]

        if isinstance(self.parent.command, Command):
            for param in self.parent.command.get_params(self):
                parent_command_path.extend(param.get_usage_pieces(self))

        rv = f"{' '.join(parent_command_path)} {rv}"
    return rv.lstrip()

def find_root(self) -> Context:
    """Finds the outermost context."""
    node = self
    while node.parent is not None:
        node = node.parent
    return node

def find_object(self, object_type: type[V]) -> V | None:
    """Finds the closest object of a given type."""
    node: Context | None = self

    while node is not None:
        if isinstance(node.obj, object_type):
            return node.obj

        node = node.parent

    return None

def ensure_object(self, object_type: type[V]) -> V:
    """Like :meth:`find_object` but sets the innermost object to a
    new instance of `object_type` if it does not exist.
    """
    rv = self.find_object(object_type)
    if rv is None:
        self.obj = rv = object_type()
    return rv

@t.overload
def lookup_default(
    self, name: str, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def lookup_default(
    self, name: str, call: t.Literal[False] = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def lookup_default(self, name: str, call: bool = True) -> t.Any | None:
    """Get the default for a parameter from :attr:`default_map`.

    :param name: Name of the parameter.
    :param call: If the default is a callable, call it. Disable to
        return the callable instead.

    .. versionchanged:: 8.0
        Added the ``call`` parameter.
    """
    if self.default_map is not None:
        value = self.default_map.get(name)

        if call and callable(value):
            return value()

        return value

    return None

def fail(self, message: str) -> t.NoReturn:
    """Aborts the execution of the program with a specific error
    message.

    :param message: the error message to fail with.
    """
    raise UsageError(message, self)

def abort(self) -> t.NoReturn:
    """Aborts the script."""
    raise Abort()

def exit(self, code: int = 0) -> t.NoReturn:
    """Exits the application with a given exit code.

    .. versionchanged:: 8.2
        Force closing of callbacks registered with
        :meth:`call_on_close` before exiting the CLI.
    """
    self.close()
    raise Exit(code)

def get_usage(self) -> str:
    """Helper method to get formatted usage string for the current
    context and command.
    """
    return self.command.get_usage(self)

def get_help(self) -> str:
    """Helper method to get formatted help page for the current
    context and command.
    """
    return self.command.get_help(self)

def _make_sub_context(self, command: Command) -> Context:
    """Create a new context of the same type as this context, but
    for a new command.

    :meta private:
    """
    return type(self)(command, info_name=command.name, parent=self)

@t.overload
def invoke(

def invoke(
    self, callback: t.Callable[..., V], /, *args: t.Any, **kwargs: t.Any
) -> V: ...

@t.overload
def invoke(self, callback: Command, /, *args: t.Any, **kwargs: t.Any) -> t.Any: ...

def invoke(
    self, callback: Command | t.Callable[..., V], /, *args: t.Any, **kwargs: t.Any
) -> t.Any | V:
    """Invokes a command callback in exactly the way it expects.  There
    are two ways to invoke this method:

    1.  the first argument can be a callback and all other arguments and
        keyword arguments are forwarded directly to the function.
    2.  the first argument is a click command object.  In that case all
        arguments are forwarded as well but proper click parameters
        (options and click arguments) must be keyword arguments and Click
        will fill in defaults.

    .. versionchanged:: 8.0
        All ``kwargs`` are tracked in :attr:`params` so they will be
        passed if :meth:`forward` is called at multiple levels.

    .. versionchanged:: 3.2
        A new context is created, and missing arguments use default values.
    """
    if isinstance(callback, Command):
        other_cmd = callback

        if other_cmd.callback is None:
            raise TypeError(
                "The given command does not have a callback that can be invoked."
            )
        else:
            callback = t.cast("t.Callable[..., V]", other_cmd.callback)

        ctx = self._make_sub_context(other_cmd)

        for param in other_cmd.params:
            if param.name not in kwargs and param.expose_value:
                kwargs[param.name] = param.type_cast_value(  # type: ignore
                    ctx, param.get_default(ctx)
                )

